UPDATE PA_ADJUST SET ADJ_TYP=#{adjTyp}, VD_CD=#{vdCd}, VD_NM=#{vdNm}, GR_ID=#{grId}, GR_NO=#{grNo}, ADJ_YM=#{adjYm}, TAX_TYP=NVL(#{taxTyp},'TAX'),
       SUPL_ADJ_AMT=#{suplAdjAmt}, VAT_ADJ_AMT=#{vatAdjAmt}, TOT_ADJ_AMT=#{totAdjAmt}, REASON=#{reason},
       REMARK=#{remark}, MOD_ID=#{modId}, MOD_DT=SYSTIMESTAMP WHERE ID=#{id}
